body:
Spin off from #6872 that will ultimately make fixing that simpler.

The below fails (along with most dependent and nested interface localparam assignments).  I have working in my sandbox arbitrary nesting and dependent assignments as well as hierarchical access.  Will take me some time yet to get it cleaned up.

```
package sc;
  typedef struct packed {
    int unsigned Capacity;
    int unsigned LineSize;
  } cfg_t;
endpackage

interface simple_cache_types_if #(
  parameter sc::cfg_t cfg = 0
)();

  localparam int  SC_NUM_LINES = cfg.Capacity / cfg.LineSize;

  typedef logic [(cfg.Capacity / cfg.LineSize)-1:0] sc_num_lines_t;

endinterface

interface simple_cache_if #(
  parameter sc::cfg_t cfg = 0
)();
  simple_cache_types_if #(cfg) types();

endinterface

module simple_cache #(parameter sc::cfg_t cfg=0) (
  simple_cache_if io
);

  localparam int  SC_NUM_LINES = io.types.SC_NUM_LINES;

  typedef io.types.sc_num_lines_t sc_num_lines_t;

  initial begin
    #1;
    $display("SC_NUM_LINES = %d", SC_NUM_LINES);  // <--- this evaluates to 'x'
    $display("bits SC_NUM_LINES = %d", $bits(sc_num_lines_t));  // <--- this correctly evalulates to '16'
    `checkd(SC_NUM_LINES, 16);
    `checkd($bits(sc_num_lines_t), 16);
  end
endmodule
```

